let result;
try { result = JSON.parse(content); } catch(e) {
  const match = content.match(/\{[\s\S]*\}/);
  result = match ? JSON.parse(match[0]) : {suggestions: [], telegram_message: 'No hay sugerencias disponibles esta semana.'};
}
return [{json: result}];
